     1→/**
     2→ * MMS Optimizer Worker Processor
     3→ *
     4→ * BullMQ job processor for run assignment optimization.
     5→ * Handles job lifecycle, progress reporting, and result storage.
     6→ *
     7→ * Job Flow:
     8→ * 1. Receive OptimizerJobData from queue
     9→ * 2. Fetch trains, routes, constraints from database
    10→ * 3. Build OptimizerFullInput
    11→ * 4. Run optimizer (C++ or fallback)
    12→ * 5. Store results and broadcast via WebSocket
    13→ *
    14→ * @see specs/002-architecture.md Section 2.2.4
    15→ * @see specs/004-domain-services.md Section 4.3
    16→ */
    17→
    18→import { logger } from '../../lib/logging/logger';
    19→import { withSpan } from '../../lib/tracing';
    20→import { db } from '../../lib/db/connection';
    21→import { ValidationError } from '../../lib/errors';
    22→import { optimizerMetrics } from '../../lib/metrics';
    23→import { type WorkerJobContext } from '../index';
    24→import { type OptimizerJobData } from '../../lib/queue';
    25→import {
    26→  runAssignmentOptimizer,
    27→  type OptimizerFullInput,
    28→  type OptimizerFullResult,
    29→  type OptimizerTrainInput,
    30→  type OptimizerRouteInput,
    31→  type HardConstraint,
    32→  type SoftConstraint,
    33→  type UnavailabilityEvent,
    34→  type ServiceDemand,
    35→  DEFAULT_OPTIMIZER_CONFIG,
    36→} from '../../optimizer';
    37→
    38→// Import database schemas
    39→import { trains, fleets, unavailabilityEvents, serviceDemand, runAssignments } from '../../lib/db/schema';
    40→import { eq, and, sql } from 'drizzle-orm';
    41→
    42→// =============================================================================
    43→// Worker Configuration
    44→// =============================================================================
    45→
    46→const log = logger.child({ worker: 'optimizer' });
    47→
    48→// =============================================================================
    49→// Job Processor
    50→// =============================================================================
    51→
    52→/**
    53→ * Process optimizer job
    54→ *
    55→ * Fetches required data, builds input, runs optimization,
    56→ * and stores/broadcasts results.
    57→ */
    58→export async function processOptimizerJob(
    59→  context: WorkerJobContext<OptimizerJobData>
    60→): Promise<OptimizerFullResult> {
    61→  return withSpan('worker.optimizer.process', async (span) => {
    62→    const { id, data } = context;
    63→    const { date, fleetId, constraints, timeoutMs } = data;
    64→
    65→    span.setAttribute('jobId', id);
    66→    span.setAttribute('date', date);
    67→    span.setAttribute('fleetId', fleetId);
    68→    span.setAttribute('hasConstraints', !!constraints);
    69→
    70→    log.info({ jobId: id, date, fleetId }, 'Processing optimizer job');
    71→
    72→    // Update progress: fetching data
    73→    await context.updateProgress({ stage: 'FETCHING_DATA', percent: 10 });
    74→    await context.log('Fetching trains and routes from database');
    75→
    76→    // Build optimizer input
    77→    const input = await buildOptimizerInput(date, fleetId, constraints, timeoutMs);
    78→
    79→    // Update progress: optimizing
    80→    await context.updateProgress({ stage: 'OPTIMIZING', percent: 30 });
    81→    await context.log(`Starting optimization for ${input.trains.length} trains, ${input.routes.length} routes`);
    82→
    83→    // Run optimization with progress callback
    84→    const result = await runAssignmentOptimizer.optimize(input, async (progress) => {
    85→      await context.updateProgress({
    86→        stage: 'OPTIMIZING',
    87→        percent: 30 + Math.floor(progress.percent * 0.6),
    88→        objective: progress.currentObjective,
    89→        feasible: progress.feasible,
    90→      });
    91→    });
    92→
    93→    // Update progress: storing results
    94→    await context.updateProgress({ stage: 'STORING_RESULTS', percent: 95 });
    95→    await context.log(`Optimization complete: ${result.summary.trainsAssigned} trains assigned`);
    96→
    97→    // Store run assignments to database for historical analysis
    98→    await storeOptimizationResults(date, input.requestId, result);
    99→
   100→    // Broadcast via WebSocket (to be implemented when WebSocket hub exists)
   101→    // await broadcastOptimizationComplete(date, fleetId, result);
   102→
   103→    // Update metrics
   104→    optimizerMetrics.trainsAssigned
   105→      .labels(fleetId)
   106→      .set(result.summary.trainsAssigned);
   107→
   108→    log.info(
   109→      {
   110→        jobId: id,
   111→        status: result.status,
   112→        trainsAssigned: result.summary.trainsAssigned,
   113→        trainsUnassigned: result.summary.trainsUnassigned,
   114→        solveTimeMs: result.solveTimeMs,
   115→      },
   116→      'Optimizer job complete'
   117→    );
   118→
   119→    return result;
   120→  });
   121→}
   122→
   123→/**
   124→ * Build optimizer input from database
   125→ */
   126→async function buildOptimizerInput(
   127→  date: string,
   128→  fleetId: string,
   129→  constraints?: OptimizerJobData['constraints'],
   130→  timeoutMs?: number
   131→): Promise<OptimizerFullInput> {
   132→  const requestId = crypto.randomUUID();
   133→
   134→  // Fetch fleet info
   135→  const fleet = await db.query.fleets.findFirst({
   136→    where: eq(fleets.id, fleetId),
   137→  });
   138→
   139→  if (!fleet) {
   140→    throw new ValidationError('Fleet not found', {
   141→      field: 'fleetId',
   142→      context: { fleetId },
   143→    });
   144→  }
   145→
   146→  // Fetch trains for this fleet
   147→  const trainRecords = await db.query.trains.findMany({
   148→    where: eq(trains.fleetId, fleetId),
   149→  });
   150→
   151→  if (trainRecords.length === 0) {
   152→    throw new ValidationError('No trains found for fleet', {
   153→      field: 'fleetId',
   154→      context: { fleetId },
   155→    });
   156→  }
   157→
   158→  // Calculate fleet average mileage for target calculation
   159→  const totalMileage = trainRecords.reduce(
   160→    (sum, t) => sum + (t.currentMileageKm || 0),
   161→    0
   162→  );
   163→  const avgMileage = Math.round(totalMileage / trainRecords.length);
   164→
   165→  // Transform trains
   166→  const baseDepotId = fleet.baseDepotId || '';
   167→  const optimizerTrains: OptimizerTrainInput[] = trainRecords.map((t) => ({
   168→    id: t.id,
   169→    trainNumber: t.trainNumber,
   170→    fleetId: t.fleetId,
   171→    currentMileageKm: t.currentMileageKm || 0,
   172→    targetMileageKm: t.targetMileageKm || avgMileage,
   173→    fitnessStatus: t.fitnessStatus as 'FIT' | 'RESTRICTED' | 'GROUNDED',
   174→    restrictions: [],
   175→    homeDepotId: baseDepotId,
   176→    currentDepotId: baseDepotId,
   177→  }));
   178→
   179→  // Fetch routes
   180→  const routeRecords = await db.query.routes.findMany();
   181→
   182→  // Filter routes compatible with this fleet
   183→  const compatibleRoutes = routeRecords.filter((r) => {
   184→    if (!r.allowedFleetIds || r.allowedFleetIds.length === 0) {
   185→      return true; // No restriction means all fleets allowed
   186→    }
   187→    return r.allowedFleetIds.includes(fleetId);
   188→  });
   189→
   190→  // Transform routes
   191→  const optimizerRoutes: OptimizerRouteInput[] = compatibleRoutes.map((r) => ({
   192→    id: r.id,
   193→    routeCode: r.routeCode,
   194→    expectedKmPerDay: r.expectedKmPerDay || 250,
   195→    requiredTrains: r.requiredTrains || 1,
   196→    allowedFleetIds: r.allowedFleetIds || [],
   197→    restrictions: [],
   198→  }));
   199→
   200→  // Build hard constraints
   201→  const hardConstraints: HardConstraint[] = [];
   202→
   203→  // Add unavailable trains from constraints
   204→  if (constraints?.unavailableTrains) {
   205→    for (const trainId of constraints.unavailableTrains) {
   206→      hardConstraints.push({
   207→        type: 'UNAVAILABLE',
   208→        trainId,
   209→        description: 'Train marked as unavailable for this assignment',
   210→      });
   211→    }
   212→  }
   213→
   214→  // Fetch active unavailability events
   215→  const unavailabilityRecords = await db.query.unavailabilityEvents.findMany({
   216→    where: and(
   217→      eq(unavailabilityEvents.status, 'ACTIVE'),
   218→    ),
   219→  });
   220→
   221→  const unavailabilityEventsList: UnavailabilityEvent[] = unavailabilityRecords
   222→    .filter((e) => optimizerTrains.some((t) => t.id === e.trainId))
   223→    .map((e) => ({
