     1→/**
     2→ * MMS Ingestion Worker Processor
     3→ *
     4→ * BullMQ job processor for CSV file ingestion.
     5→ * Handles mileage data import, anomaly detection, and meter event processing.
     6→ *
     7→ * Job Flow:
     8→ * 1. Receive IngestionJobData from queue (filePath, fileName, fileSize)
     9→ * 2. Parse and validate CSV records
    10→ * 3. Detect anomalies (negative mileage, spikes, duplicates)
    11→ * 4. Process meter events (resets, replacements)
    12→ * 5. Store results and update train mileage
    13→ *
    14→ * @see specs/004-domain-services.md Section 4.2.3
    15→ */
    16→
    17→import { logger } from '../../lib/logging/logger';
    18→import { withSpan } from '../../lib/tracing';
    19→import { type WorkerJobContext } from '../index';
    20→import { type IngestionJobData } from '../../lib/queue';
    21→import { getIngestionService, type IngestionResult } from '../../services';
    22→import { ingestionMetrics, recordIngestionComplete } from '../../lib/metrics';
    23→
    24→// =============================================================================
    25→// Worker Configuration
    26→// =============================================================================
    27→
    28→const log = logger.child({ worker: 'ingestion' });
    29→
    30→// =============================================================================
    31→// Job Processor
    32→// =============================================================================
    33→
    34→/**
    35→ * Process ingestion job
    36→ *
    37→ * Parses CSV mileage file, validates records, detects anomalies,
    38→ * and stores results in the database.
    39→ */
    40→export async function processIngestionJob(
    41→  context: WorkerJobContext<IngestionJobData>
    42→): Promise<IngestionResult> {
    43→  return withSpan('worker.ingestion.process', async (span) => {
    44→    const { id, data } = context;
    45→    const { filePath, fileName, fileSize } = data;
    46→
    47→    span.setAttribute('jobId', id);
    48→    span.setAttribute('filePath', filePath);
    49→    span.setAttribute('fileName', fileName);
    50→    span.setAttribute('fileSize', fileSize);
    51→
    52→    log.info(
    53→      { jobId: id, fileName, fileSize },
    54→      'Processing ingestion job'
    55→    );
    56→
    57→    // Update progress: parsing file
    58→    await context.updateProgress({ stage: 'PARSING', percent: 10 });
    59→    await context.log(`Parsing file: ${fileName} (${formatFileSize(fileSize)})`);
    60→
    61→    // Get ingestion service
    62→    const ingestionService = getIngestionService();
    63→
    64→    // Update progress: validating
    65→    await context.updateProgress({ stage: 'VALIDATING', percent: 20 });
    66→    await context.log('Validating CSV records');
    67→
    68→    // Process the file
    69→    // The service's processFile method handles:
    70→    // - CSV parsing with PapaParse
    71→    // - Record validation (train existence, date format, mileage values)
    72→    // - Anomaly detection (negative, spike, duplicate)
    73→    // - Meter event detection and adjustment calculation
    74→    // - Batch database inserts
    75→    // - Train mileage updates
    76→    const result = await ingestionService.processFile(filePath, id);
    77→
    78→    // Update progress based on processing stages
    79→    if (result.totalRecords > 0) {
    80→      const validPct = Math.round((result.validRecords / result.totalRecords) * 100);
    81→      await context.updateProgress({
    82→        stage: 'STORING',
    83→        percent: 70,
    84→        validPercent: validPct,
    85→      });
    86→      await context.log(
    87→        `Validated ${result.validRecords}/${result.totalRecords} records (${validPct}%)`
    88→      );
    89→    }
    90→
    91→    // Update progress: finalizing
    92→    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });
    93→
    94→    // Log results
    95→    log.info(
    96→      {
    97→        jobId: id,
    98→        status: result.status,
    99→        totalRecords: result.totalRecords,
   100→        validRecords: result.validRecords,
   101→        invalidRecords: result.invalidRecords,
   102→        anomalies: result.anomalies.length,
   103→        meterEvents: result.meterEvents.length,
   104→        processingTimeMs: result.processingTimeMs,
   105→      },
   106→      'Ingestion job complete'
   107→    );
   108→
   109→    await context.log(
   110→      `Ingestion complete: ${result.validRecords} valid, ` +
   111→        `${result.invalidRecords} invalid, ${result.anomalies.length} anomalies`
   112→    );
   113→
   114→    // Log anomalies
   115→    if (result.anomalies.length > 0) {
   116→      log.warn(
   117→        {
   118→          jobId: id,
   119→          anomalyTypes: result.anomalies.reduce(
   120→            (acc, a) => {
   121→              acc[a.type] = (acc[a.type] || 0) + 1;
   122→              return acc;
   123→            },
   124→            {} as Record<string, number>
   125→          ),
   126→        },
   127→        'Anomalies detected during ingestion'
   128→      );
   129→
   130→      for (const anomaly of result.anomalies.slice(0, 5)) {
   131→        await context.log(
   132→          `Anomaly: ${anomaly.type} for train ${anomaly.trainNumber} on ${anomaly.readingDate}`
   133→        );
   134→      }
   135→
   136→      if (result.anomalies.length > 5) {
   137→        await context.log(`... and ${result.anomalies.length - 5} more anomalies`);
   138→      }
   139→    }
   140→
   141→    // Log meter events
   142→    if (result.meterEvents.length > 0) {
   143→      log.info(
   144→        { jobId: id, meterEventCount: result.meterEvents.length },
   145→        'Meter events detected'
   146→      );
   147→
   148→      for (const event of result.meterEvents) {
   149→        await context.log(
   150→          `Meter event: ${event.eventType} for train ${event.trainId} ` +
   151→            `(adjustment: ${event.adjustmentKm} km)`
   152→        );
   153→      }
   154→    }
   155→
   156→    // Update metrics
   157→    span.setAttribute('ingestion.totalRecords', result.totalRecords);
   158→    span.setAttribute('ingestion.validRecords', result.validRecords);
   159→    span.setAttribute('ingestion.invalidRecords', result.invalidRecords);
   160→    span.setAttribute('ingestion.anomalyCount', result.anomalies.length);
   161→    span.setAttribute('ingestion.meterEventCount', result.meterEvents.length);
   162→    span.setAttribute('ingestion.processingTimeMs', result.processingTimeMs);
   163→    span.setAttribute('ingestion.status', result.status);
   164→
   165→    // Record to Prometheus
   166→    recordIngestionComplete(
   167→      result.status === 'SUCCESS' ? 'SUCCESS' : result.status === 'PARTIAL' ? 'PARTIAL' : 'FAILED',
   168→      result.processingTimeMs
   169→    );
   170→    ingestionMetrics.recordsProcessed
   171→      .labels('total')
   172→      .inc(result.totalRecords);
   173→    ingestionMetrics.recordsProcessed
   174→      .labels('valid')
   175→      .inc(result.validRecords);
   176→    ingestionMetrics.recordsProcessed
   177→      .labels('invalid')
   178→      .inc(result.invalidRecords);
   179→
   180→    // Update progress: complete
   181→    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });
   182→
   183→    return result;
   184→  });
   185→}
   186→
   187→/**
   188→ * Format file size for human-readable display
   189→ */
   190→function formatFileSize(bytes: number): string {
   191→  if (bytes < 1024) return `${bytes} B`;
   192→  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
   193→  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
   194→}
