 * MMS Ingestion Worker Processor
 *
 * BullMQ job processor for CSV file ingestion.
 * Handles mileage data import, anomaly detection, and meter event processing.
 *
 * Job Flow:
 * 1. Receive IngestionJobData from queue (filePath, fileName, fileSize)
 * 2. Parse and validate CSV records
 * 3. Detect anomalies (negative mileage, spikes, duplicates)
 * 4. Process meter events (resets, replacements)
 * 5. Store results and update train mileage
 *
 * @see specs/004-domain-services.md Section 4.2.3
 */

import { logger } from '../../lib/logging/logger';
import { withSpan } from '../../lib/tracing';
import { type WorkerJobContext } from '../index';
import { type IngestionJobData } from '../../lib/queue';
import { getIngestionService, type IngestionResult } from '../../services';
import { ingestionMetrics, recordIngestionComplete } from '../../lib/metrics';

// =============================================================================
// Worker Configuration
// =============================================================================

const log = logger.child({ worker: 'ingestion' });

// =============================================================================
// Job Processor
// =============================================================================

/**
 * Process ingestion job
 *
 * Parses CSV mileage file, validates records, detects anomalies,
 * and stores results in the database.
 */
export async function processIngestionJob(
  context: WorkerJobContext<IngestionJobData>
): Promise<IngestionResult> {
  return withSpan('worker.ingestion.process', async (span) => {
    const { id, data } = context;
    const { filePath, fileName, fileSize } = data;

    span.setAttribute('jobId', id);
    span.setAttribute('filePath', filePath);
    span.setAttribute('fileName', fileName);
    span.setAttribute('fileSize', fileSize);

    log.info(
      { jobId: id, fileName, fileSize },
      'Processing ingestion job'
    );

    // Update progress: parsing file
    await context.updateProgress({ stage: 'PARSING', percent: 10 });
    await context.log(`Parsing file: ${fileName} (${formatFileSize(fileSize)})`);

    // Get ingestion service
    const ingestionService = getIngestionService();

    // Update progress: validating
    await context.updateProgress({ stage: 'VALIDATING', percent: 20 });
    await context.log('Validating CSV records');

    // Process the file
    // The service's processFile method handles:
    // - CSV parsing with PapaParse
    // - Record validation (train existence, date format, mileage values)
    // - Anomaly detection (negative, spike, duplicate)
    // - Meter event detection and adjustment calculation
    // - Batch database inserts
    // - Train mileage updates
    const result = await ingestionService.processFile(filePath, id);

    // Update progress based on processing stages
    if (result.totalRecords > 0) {
      const validPct = Math.round((result.validRecords / result.totalRecords) * 100);
      await context.updateProgress({
        stage: 'STORING',
        percent: 70,
        validPercent: validPct,
      });
      await context.log(
        `Validated ${result.validRecords}/${result.totalRecords} records (${validPct}%)`
      );
    }

    // Update progress: finalizing
    await context.updateProgress({ stage: 'FINALIZING', percent: 90 });

    // Log results
    log.info(
      {
        jobId: id,
        status: result.status,
        totalRecords: result.totalRecords,
        validRecords: result.validRecords,
        invalidRecords: result.invalidRecords,
        anomalies: result.anomalies.length,
        meterEvents: result.meterEvents.length,
        processingTimeMs: result.processingTimeMs,
      },
      'Ingestion job complete'
    );

    await context.log(
      `Ingestion complete: ${result.validRecords} valid, ` +
        `${result.invalidRecords} invalid, ${result.anomalies.length} anomalies`
    );

    // Log anomalies
    if (result.anomalies.length > 0) {
      log.warn(
        {
          jobId: id,
          anomalyTypes: result.anomalies.reduce(
            (acc, a) => {
              acc[a.type] = (acc[a.type] || 0) + 1;
              return acc;
            },
            {} as Record<string, number>
          ),
        },
        'Anomalies detected during ingestion'
      );

      for (const anomaly of result.anomalies.slice(0, 5)) {
        await context.log(
          `Anomaly: ${anomaly.type} for train ${anomaly.trainNumber} on ${anomaly.readingDate}`
        );
      }

      if (result.anomalies.length > 5) {
        await context.log(`... and ${result.anomalies.length - 5} more anomalies`);
      }
    }

    // Log meter events
    if (result.meterEvents.length > 0) {
      log.info(
        { jobId: id, meterEventCount: result.meterEvents.length },
        'Meter events detected'
      );

      for (const event of result.meterEvents) {
        await context.log(
          `Meter event: ${event.eventType} for train ${event.trainId} ` +
            `(adjustment: ${event.adjustmentKm} km)`
        );
      }
    }

    // Update metrics
    span.setAttribute('ingestion.totalRecords', result.totalRecords);
    span.setAttribute('ingestion.validRecords', result.validRecords);
    span.setAttribute('ingestion.invalidRecords', result.invalidRecords);
    span.setAttribute('ingestion.anomalyCount', result.anomalies.length);
    span.setAttribute('ingestion.meterEventCount', result.meterEvents.length);
    span.setAttribute('ingestion.processingTimeMs', result.processingTimeMs);
    span.setAttribute('ingestion.status', result.status);

    // Record to Prometheus
    recordIngestionComplete(
      result.status === 'SUCCESS' ? 'SUCCESS' : result.status === 'PARTIAL' ? 'PARTIAL' : 'FAILED',
      result.processingTimeMs
    );
    ingestionMetrics.recordsProcessed
      .labels('total')
      .inc(result.totalRecords);
    ingestionMetrics.recordsProcessed
      .labels('valid')
      .inc(result.validRecords);
    ingestionMetrics.recordsProcessed
      .labels('invalid')
      .inc(result.invalidRecords);

    // Update progress: complete
    await context.updateProgress({ stage: 'COMPLETE', percent: 100 });

    return result;
  });
}

/**
 * Format file size for human-readable display
 */
function formatFileSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

/**
 * Register the ingestion worker
 */
export function registerIngestionWorker(): void {
  log.info('Ingestion worker processor available for registration');
}

