/**
 * MMS Optimizer Types
 *
 * Type definitions for the run assignment optimizer.
 * These extend the base schemas to include all fields needed
 * for constraint validation and explanation generation.
 *
 * @see specs/002-architecture.md Section 2.4
 * @see specs/004-domain-services.md Section 4.3
 */

// =============================================================================
// Input Types
// =============================================================================

/**
 * Train data for optimization
 */
export interface OptimizerTrainInput {
  id: string;
  trainNumber: string;
  fleetId: string;
  currentMileageKm: number;
  targetMileageKm: number;
  fitnessStatus: 'FIT' | 'RESTRICTED' | 'GROUNDED';
  restrictions: string[];
  homeDepotId: string;
  currentDepotId: string;
}

/**
 * Route data for optimization
 */
export interface OptimizerRouteInput {
  id: string;
  routeCode: string;
  expectedKmPerDay: number;
  requiredTrains: number;
  allowedFleetIds: string[];
  restrictions: string[];
}

/**
 * Hard constraint that must not be violated
 */
export interface HardConstraint {
  type: 'PM_DUE' | 'GROUNDED' | 'DEPOT_LOCK' | 'CERTIFICATION' | 'UNAVAILABLE' | 'INCOMPATIBLE';
  trainId: string;
  routeId?: string;
  description: string;
}

/**
 * Soft constraint with penalty weight
 */
export interface SoftConstraint {
  type: 'MILEAGE_BALANCE' | 'DEPOT_PREFERENCE' | 'ROUTE_PREFERENCE';
  trainId: string;
  penaltyWeight: number;
  description: string;
}

/**
 * Unavailability event blocking train assignment
 */
export interface UnavailabilityEvent {
  trainId: string;
  eventType: 'CORRECTIVE' | 'INCIDENT' | 'COLLISION' | 'VANDALISM' | 'EXTERNAL' | 'PLANNED_OUTAGE';
  status: 'ACTIVE' | 'RESOLVED';
  blocksRunAssignment: boolean;
  description?: string;
  externalReference?: string;
}

/**
 * Route compatibility record
 */
export interface RouteCompatibility {
  trainId?: string;
  fleetId?: string;
  routeId: string;
  isCompatible: boolean;
  constraintType?: string;
  restrictionReason?: string;
}

/**
 * Material position at depot
 */
export interface MaterialPosition {
  depotId: string;
  partNumber: string;
  quantityAvailable: number;
  nextDeliveryDate?: string;
}

/**
 * Material requirement for PM
 */
export interface MaterialRequirement {
  partNumber: string;
  quantity: number;
  criticality: 'BLOCKING' | 'DEFERRABLE' | 'CONSUMABLE';
}

/**
 * Pending PM that may block assignment
 */
export interface PendingPm {
  pmId: string;
  trainId: string;
  pmType: string;
  targetDate: string;
  requiredMaterials: MaterialRequirement[];
}

/**
 * Service demand requirement
 */
export interface ServiceDemand {
  fleetId: string;
  minTrainsRequired: number;
  dayType: 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';
}

/**
 * Optimizer configuration
 */
export interface OptimizerConfig {
  maxSolveTimeSeconds: number;
  numWorkers: number;
  softConstraintPenalties: {
    mileageImbalance: number;
    preferenceViolation: number;
    overtimeHours: number;
  };
  explanationVerbosity: 'MINIMAL' | 'STANDARD' | 'DETAILED';
}

/**
 * Complete optimizer input
 */
export interface OptimizerFullInput {
  requestId: string;
  assignmentDate: string;
  config: OptimizerConfig;
  trains: OptimizerTrainInput[];
  routes: OptimizerRouteInput[];
  hardConstraints: HardConstraint[];
  softConstraints: SoftConstraint[];
  unavailabilityEvents?: UnavailabilityEvent[];
  routeCompatibility?: RouteCompatibility[];
  materialPositions?: MaterialPosition[];
  pendingPms?: PendingPm[];
  serviceDemand?: ServiceDemand[];
}

// =============================================================================
// Output Types
// =============================================================================

/**
 * Explanation trace for an assignment decision
 */
export interface ExplanationTrace {
  constraintType: 'HARD' | 'SOFT';
  constraintName: string;
  impact: number;
  description: string;
}

/**
 * Train-to-route assignment
 */
export interface Assignment {
  trainId: string;
  routeId: string;
  score: number;
  explanation: ExplanationTrace[];
}

/**
 * Train that could not be assigned
 */
export interface UnassignedTrain {
  trainId?: string;
  routeId?: string;
  shortfall?: number;
  reason: string;
  blockingConstraints: string[];
}

/**
 * Material warning for pending PM
 */
export interface MaterialWarning {
  pmId: string;
  trainId: string;
  partNumber: string;
  status: 'UNAVAILABLE' | 'LOW_STOCK' | 'ARRIVING_LATE';
  description: string;
}

/**
 * Result summary
 */
export interface ResultSummary {
  totalPenalty: number;
  trainsAssigned: number;
  trainsUnassigned: number;
  softConstraintBreakdown: Record<string, number>;
  materialBlocks: number;
}

/**
 * Optimizer result status
 */
export type OptimizerStatus = 'OPTIMAL' | 'FEASIBLE' | 'FALLBACK' | 'INFEASIBLE';

/**
 * Complete optimizer result
 */
export interface OptimizerFullResult {
  type: 'RESULT';
  requestId: string;
  status: OptimizerStatus;
  solveTimeMs: number;
  assignments: Assignment[];
  unassigned: UnassignedTrain[];
  materialWarnings: MaterialWarning[];
  summary: ResultSummary;
}

/**
 * Progress update during optimization
 */
export interface OptimizerProgressMessage {
  type: 'PROGRESS';
  requestId: string;
  percent: number;
  currentObjective: number;
  feasible: boolean;
  elapsedMs: number;
}

/**
 * Heartbeat message during optimization
 */
export interface OptimizerHeartbeatMessage {
  type: 'HEARTBEAT';
  requestId: string;
  timestamp: number;
  memoryMb: number;
  threadCount: number;
  branchesPerSecond: number;
}

/**
 * Error message from optimizer
 */
export interface OptimizerErrorMessage {
  type: 'ERROR';
  requestId: string;
  errorCode: 'SEGFAULT' | 'TIMEOUT' | 'OOM' | 'INVALID_INPUT' | 'INTERNAL_ERROR';
  errorMessage: string;
  stackTrace?: string;
  lastProgress?: {
    percent: number;
    branchesExplored: number;
    memoryMb: number;
  };
  recoverySuggestion: string;
}

/**
 * Union of all optimizer output messages
 */
export type OptimizerMessage =
  | OptimizerProgressMessage
  | OptimizerHeartbeatMessage
  | OptimizerErrorMessage
  | OptimizerFullResult;

// =============================================================================
// Default Configuration
// =============================================================================

export const DEFAULT_OPTIMIZER_CONFIG: OptimizerConfig = {
  maxSolveTimeSeconds: 30,
  numWorkers: 4,
  softConstraintPenalties: {
    mileageImbalance: 100,
    preferenceViolation: 50,
    overtimeHours: 200,
  },
  explanationVerbosity: 'STANDARD',
};

